class Solution:
    def maxProfit(self, n, present, future, hierarchy, budget):
        boss = {}
        for u, v in hierarchy:
            boss[v] = u
        best = 0
        for mask in range(1 << n):
            bought = [(mask >> i) & 1 for i in range(n)]
            cost = 0
            prof = 0
            for e in range(1, n + 1):
                if bought[e - 1]:
                    b = boss.get(e)
                    disc = b is not None and bought[b - 1]
                    price = present[e - 1] // 2 if disc else present[e - 1]
                    cost += price
                    prof += future[e - 1] - price
            if cost <= budget and prof > best:
                best = prof
        return best

