import sys
class Solution:
    def maxProfit(self, n, present, future, hierarchy, budget):
        sys.setrecursionlimit(1000)
        children = [[] for _ in range(n + 1)]
        for u, v in hierarchy:
            children[u].append(v)
        NEG = float('-inf')
        def combine(child_list, child_disc):
            cur = [NEG] * (budget + 1)
            cur[0] = 0
            for ch in child_list:
                cdp = solve(ch, child_disc)
                nxt = [NEG] * (budget + 1)
                for c in range(budget + 1):
                    if cur[c] == NEG:
                        continue
                    base = cur[c]
                    for cc in range(budget + 1 - c):
                        if cdp[cc] == NEG:
                            continue
                        val = base + cdp[cc]
                        if val > nxt[c + cc]:
                            nxt[c + cc] = val
                cur = nxt
            return cur
        def solve(node, discounted):
            full = present[node - 1]
            price = full // 2 if discounted else full
            prof_self = future[node - 1] - price
            res = combine(children[node], False)[:]
            if price <= budget:
                buychildren = combine(children[node], True)
                for c in range(budget + 1):
                    if buychildren[c] == NEG:
                        continue
                    tc = c + price
                    if tc <= budget:
                        val = buychildren[c] + prof_self
                        if val > res[tc]:
                            res[tc] = val
            return res
        arr = solve(1, False)
        best = 0
        for c in range(budget + 1):
            if arr[c] != NEG and arr[c] > best:
                best = arr[c]
        return best

