var maxProfit = function(n, present, future, hierarchy, budget) {
    const children = Array.from({length: n + 1}, () => []);
    for (const [u, v] of hierarchy) children[u].push(v);
    const NEG = -Infinity;
    function combine(childList, childDisc) {
        let cur = new Array(budget + 1).fill(NEG);
        cur[0] = 0;
        for (const ch of childList) {
            const cdp = solve(ch, childDisc);
            const nxt = new Array(budget + 1).fill(NEG);
            for (let c = 0; c <= budget; c++) {
                if (cur[c] === NEG) continue;
                const base = cur[c];
                for (let cc = 0; cc <= budget - c; cc++) {
                    if (cdp[cc] === NEG) continue;
                    const val = base + cdp[cc];
                    if (val > nxt[c + cc]) nxt[c + cc] = val;
                }
            }
            cur = nxt;
        }
        return cur;
    }
    function solve(node, discounted) {
        const full = present[node - 1];
        const price = discounted ? Math.floor(full / 2) : full;
        const profSelf = future[node - 1] - price;
        const res = combine(children[node], false).slice();
        if (price <= budget) {
            const buychildren = combine(children[node], true);
            for (let c = 0; c <= budget; c++) {
                if (buychildren[c] === NEG) continue;
                const tc = c + price;
                if (tc <= budget) {
                    const val = buychildren[c] + profSelf;
                    if (val > res[tc]) res[tc] = val;
                }
            }
        }
        return res;
    }
    const arr = solve(1, false);
    let best = 0;
    for (let c = 0; c <= budget; c++) {
        if (arr[c] !== NEG && arr[c] > best) best = arr[c];
    }
    return best;
};
